struct StageswagMerchCard: View {
    let item: StageswagMerchItem
    let theme: StageswagTheme
    let onAdd: (String?) -> Void

    @State private var selectedSize: String? = nil
    @State private var showAdded = false
    private let sizes = ["S", "M", "L", "XL"]

    var body: some View {
        VStack(spacing: 10) {
            ZStack {
                RoundedRectangle(cornerRadius: 14)
                    .fill(item.accentColor.opacity(0.12))
                    .frame(height: 110)

                if showAdded {
                    VStack(spacing: 4) {
                        Image(systemName: "checkmark.circle.fill")
                            .font(.system(size: 28, weight: .semibold))
                            .foregroundStyle(.green)
                        Text("Added!")
                            .font(.system(size: 13, weight: .bold))
                            .foregroundStyle(.green)
                    }
                    .transition(.scale.combined(with: .opacity))
                } else {
                    Image(systemName: item.icon)
                        .font(.system(size: 38, weight: .light))
                        .foregroundStyle(
                            LinearGradient(
                                colors: [item.accentColor, item.accentColor.opacity(0.6)],
                                startPoint: .topLeading,
                                endPoint: .bottomTrailing
                            )
                        )
                        .transition(.scale.combined(with: .opacity))
                }
            }
            .animation(.spring(duration: 0.3), value: showAdded)

            VStack(spacing: 4) {
                Text(item.name)
                    .font(.system(size: 13, weight: .semibold))
                    .foregroundStyle(.primary)
                    .lineLimit(2, reservesSpace: true)
                    .multilineTextAlignment(.center)

                Text(String(format: "$%.2f", item.price))
                    .font(.system(size: 14, weight: .bold, design: .monospaced))
                    .foregroundStyle(item.accentColor)
            }

            // Size picker or spacer to keep cards equal height
            if item.isApparel {
                HStack(spacing: 6) {
                    ForEach(sizes, id: \.self) { size in
                        Text(size)
                            .font(.system(size: 11, weight: .semibold))
                            .foregroundStyle(selectedSize == size ? .white : .secondary)
                            .padding(.horizontal, 8)
                            .padding(.vertical, 4)
                            .background {
                                if selectedSize == size {
                                    Capsule().fill(item.accentColor)
                                } else {
                                    Capsule().fill(Color(.tertiarySystemFill))
                                }
                            }
                            .onTapGesture {
                                withAnimation(.spring(duration: 0.2)) {
                                    selectedSize = size
                                }
                            }
                    }
                }
            } else {
                // Reserve the same height as the size picker row
                Color.clear
                    .frame(height: 24)
            }

            Spacer(minLength: 0)

            Button {
                onAdd(selectedSize)
                showAdded = true
                DispatchQueue.main.asyncAfter(deadline: .now() + 1.2) {
                    showAdded = false
                    selectedSize = nil
                }
            } label: {
                HStack(spacing: 4) {
                    Image(systemName: "bag.badge.plus")
                        .font(.system(size: 12, weight: .semibold))
                    Text("Add")
                        .font(.system(size: 13, weight: .semibold))
                }
                .foregroundStyle(.white)
                .frame(maxWidth: .infinity)
                .padding(.vertical, 8)
                .background(canAdd ? item.accentColor : Color.gray.opacity(0.4), in: Capsule())
            }
            .disabled(!canAdd)
        }
        .frame(maxHeight: .infinity, alignment: .top)
        .padding(12)
        .glassEffect(.regular.interactive(), in: RoundedRectangle(cornerRadius: 18))
    }

    private var canAdd: Bool {
        !item.isApparel || selectedSize != nil
    }
}

// MARK: - From Submissions/stageswag/SetlistView.swift

struct StageswagSetlistView: View {
    let songs: [StageswagSong]
    let theme: StageswagTheme
    let launchDate: Date
    @Binding var selectedTheme: StageswagTheme
    let onSongTap: (StageswagSong) -> Void
    let cartCount: Int
    let onCheckout: () -> Void

    var body: some View {
        TimelineView(.periodic(from: .now, by: 1.0)) { timeline in
            let elapsed = timeline.date.timeIntervalSince(launchDate)

            ScrollView {
                VStack(spacing: 0) {
                    GeometryReader { geo in
                        let minY = geo.frame(in: .named("stageswagScroll")).minY
                        StageswagParallaxHeader(
                            band: StageswagMockData.band,
                            theme: theme,
                            minY: minY
                        )
                    }
                    .frame(height: 220)

                    VStack(spacing: 14) {
                        StageswagThemePicker(selectedTheme: $selectedTheme)
                            .padding(.top, 16)

                        stageswagSectionHeader("TONIGHT'S SETLIST", theme: theme)

                        ForEach(Array(songs.enumerated()), id: \.element.id) { index, song in
                            let isUnlocked = elapsed >= song.unlockOffset
                            let secondsLeft = max(0, Int(song.unlockOffset - elapsed))

                            StageswagSongRow(
                                song: song,
                                isUnlocked: isUnlocked,
                                secondsUntilUnlock: secondsLeft,
                                theme: theme,
                                onTap: { onSongTap(song) }
                            )
                            .padding(.horizontal, 16)
                            .animation(.spring(duration: 0.4).delay(Double(index) * 0.05), value: elapsed > 0)
                        }

                        if cartCount > 0 {
                            stageswagCartBanner(cartCount: cartCount, theme: theme, onCheckout: onCheckout)
                                .padding(.horizontal, 16)
                                .padding(.top, 8)
                                .transition(.move(edge: .bottom).combined(with: .opacity))
                        }
                    }
                    .padding(.bottom, 32)
                }
            }
            .coordinateSpace(name: "stageswagScroll")
            .scrollIndicators(.hidden)
            .animation(.spring(duration: 0.3), value: cartCount)
        }
    }
}

@ViewBuilder
private func stageswagSectionHeader(_ title: String, theme: StageswagTheme) -> some View {
    HStack {
        Text(title)
            .font(.system(size: 11, weight: .bold))
            .tracking(1.5)
            .foregroundStyle(theme.textHighlight.opacity(0.6))
        Spacer()
    }
    .padding(.horizontal, 20)
    .padding(.top, 8)
}

@ViewBuilder
private func stageswagCartBanner(cartCount: Int, theme: StageswagTheme, onCheckout: @escaping () -> Void) -> some View {
    Button(action: onCheckout) {
        HStack(spacing: 10) {
            Image(systemName: "bag.fill")
                .font(.system(size: 16, weight: .semibold))
            Text("View Cart (\(cartCount))")
                .font(.system(size: 15, weight: .semibold))
            Spacer()
            Image(systemName: "chevron.right")
                .font(.system(size: 13, weight: .semibold))
        }
        .foregroundStyle(.white)
        .padding(.horizontal, 18)
        .padding(.vertical, 14)
        .background(theme.accentColor, in: RoundedRectangle(cornerRadius: 16))
    }
}

